-- ═════════════════════════════════════════════════════════════════════════
-- MoviQ — BLOG i18n SEED (traduzioni manuali degli articoli "pillar")
-- ═════════════════════════════════════════════════════════════════════════
--
-- Inserisce le traduzioni en/es/de/pt/fr per gli articoli selezionati.
-- Ogni traduzione condivide lo slug dell'originale IT ed eredita
-- cover/tags/status/published_at dalla riga 'it' (così è subito pubblicata).
-- Idempotente: ON CONFLICT (slug, lang) aggiorna i campi tradotti.
--
-- Da applicare DOPO blog-i18n-schema.sql.
-- ═════════════════════════════════════════════════════════════════════════

-- Helper: inserisce/aggiorna una traduzione copiando i metadati dalla riga IT.
create or replace function public._seed_blog_tr(
  p_slug text, p_lang text, p_title text, p_excerpt text, p_content text,
  p_meta_title text default null, p_meta_description text default null
) returns void language sql as $fn$
  insert into public.blog_articles (
    slug, lang, title, excerpt, content_md, cover_image_url, tags, status,
    meta_title, meta_description, ai_generated, ai_model, author_id, published_at
  )
  select b.slug, p_lang, p_title, p_excerpt, coalesce(p_content,''),
         b.cover_image_url, b.tags, b.status, p_meta_title, p_meta_description,
         b.ai_generated, b.ai_model, b.author_id, b.published_at
    from public.blog_articles b
   where b.slug = p_slug and b.lang = 'it'
  on conflict (slug, lang) do update set
    title = excluded.title, excerpt = excluded.excerpt, content_md = excluded.content_md,
    meta_title = excluded.meta_title, meta_description = excluded.meta_description,
    cover_image_url = excluded.cover_image_url, tags = excluded.tags,
    status = excluded.status, published_at = excluded.published_at, updated_at = now();
$fn$;

